package clients.org.apache.kafka.clients;

public class ClientResponse { private final RequestHeader requestHeader ; private final RequestCompletionHandler callback ; private final String destination ; private final long receivedTimeMs ; private final long latencyMs ; private final boolean disconnected ; private final UnsupportedVersionException versionMismatch ; private final AuthenticationException authenticationException ; private final AbstractResponse responseBody ; public ClientResponse ( RequestHeader requestHeader , RequestCompletionHandler callback , String destination , long createdTimeMs , long receivedTimeMs , boolean disconnected , UnsupportedVersionException versionMismatch , AuthenticationException authenticationException , AbstractResponse responseBody ) { this . requestHeader = requestHeader ; this . callback = callback ; this . destination = destination ; this . receivedTimeMs = receivedTimeMs ; this . latencyMs = receivedTimeMs - createdTimeMs ; this . disconnected = disconnected ; this . versionMismatch = versionMismatch ; this . authenticationException = authenticationException ; this . responseBody = responseBody ; } public long receivedTimeMs ( ) { return receivedTimeMs ; } public boolean wasDisconnected ( ) { return disconnected ; } public UnsupportedVersionException versionMismatch ( ) { return versionMismatch ; } public AuthenticationException authenticationException ( ) { return authenticationException ; } public RequestHeader requestHeader ( ) { return requestHeader ; } public String destination ( ) { return destination ; } public AbstractResponse responseBody ( ) { return responseBody ; } public boolean hasResponse ( ) { return responseBody != null ; } public long requestLatencyMs ( ) { return latencyMs ; } public void onComplete ( ) { if ( callback != null ) callback . onComplete ( this ) ; } @ Override public String toString ( ) { return "ClientResponse(receivedTimeMs=" + receivedTimeMs + ", latencyMs=" + latencyMs + ", disconnected=" + disconnected + ", requestHeader=" + requestHeader + ", responseBody=" + responseBody + ")" ; } }